def normalize_scores(scores):
    if not scores:
        return []
    low = min(scores)
    high = max(scores)
    if high == low:
        return [0.0 for _ in scores]
    spread = high - low
    return [(score - low) / spread for score in scores]

print(normalize_scores([10, 20, 30]))

